(() => {
  // Access the R3F store from the React fiber
  const canvas = document.querySelector('canvas');
  if (!canvas) return 'No canvas';
  const fiberKey = Object.keys(canvas).find(k => k.startsWith('__reactFiber'));
  if (!fiberKey) return 'No fiber';

  // Walk the fiber tree to find the Canvas component's store
  let fiber = canvas[fiberKey];
  let store = null;
  let depth = 0;
  while (fiber && depth < 30) {
    if (fiber.memoizedProps && fiber.memoizedProps.store) {
      store = fiber.memoizedProps.store;
      break;
    }
    fiber = fiber.return;
    depth++;
  }

  if (!store) return 'No store found in fiber tree';

  const state = store.getState();
  const scene = state.scene;
  if (!scene) return 'Store found but no scene';

  return {
    sceneChildren: scene.children.length,
    childTypes: scene.children.map(c => c.type),
    childCount: scene.children.reduce((sum, c) => sum + (c.children ? c.children.length : 0), 0)
  };
})()

