  // Check if there's any visual content by scanning the canvas at many points
  const canvas = document.querySelector('canvas');
  const ctx = canvas.getContext('2d');
  if (!ctx) return 'No 2d context';

  // Get the actual pixel data from the rendered canvas frame
  const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
  const data = imageData.data;

  // Count non-zero pixels and find the bounding box of non-background content
  let nonWhiteCount = 0;
  let minR = 255, maxR = 0;
